591-M.jpg?default=false	https://play.google.com/books/reader?id=0avYCgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api	textbook	google_books	0avYCgAAQBAJ	{"average_rating":null,"ratings_count":null,"info_link":"https:\\/\\/books.google.co.in\\/books?id=0avYCgAAQBAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api","canonical_volume_link":"https:\\/\\/books.google.com\\/books\\/about\\/Linear_Algebra.html?hl=&id=0avYCgAAQBAJ","reader_link":"https:\\/\\/play.google.com\\/books\\/reader?id=0avYCgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api","embeddable":true,"viewability":"PARTIAL","text_to_speech_permission":"ALLOWED","public_domain":false,"pdf_available":true,"pdf_download_link":null,"epub_available":true,"epub_download_link":null}	1	2026-05-16 10:05:54	2026-05-16 10:05:54	approved	\N	\N
