xY3NAEACAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=wxY3NAEACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:16;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"z0TG81Gs0r0C";s:5:"title";s:21:"Differential Calculus";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:14:"Shanti Narayan";}s:9:"publisher";s:19:"S. Chand Publishing";s:14:"published_date";s:7:"2005-03";s:7:"isbn_10";s:10:"8121904714";s:7:"isbn_13";s:13:"9788121904711";s:8:"language";s:2:"en";s:10:"page_count";i:724;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:480:"This textbook commences with a brief outline of development of real numbers, their expression as infinite decimals and their representation by points along a line. While the first part of the textbook is analytical, the latter part deals with the geometrical applications of the subject. Numerous examples and exercises have been provided to support student's understanding. This textbook has been designed to meet the requirements of undergraduate students of BA and BSc courses.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788121904711-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=z0TG81Gs0r0C&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=z0TG81Gs0r0C&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:1;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=z0TG81Gs0r0C&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=z0TG81Gs0r0C";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=z0TG81Gs0r0C&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:17;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"FJXa0QEACAAJ";s:5:"title";s:22:"A Textbook of Calculus";s:8:"subtitle";s:36:"(differential and Integral Calculus)";s:7:"authors";a:2:{i:0;s:11:"S. C. Arora";i:1;s:12:"Ramesh Kumar";}s:9:"publisher";N;s:14:"published_date";s:4:"1992";s:7:"isbn_10";N;s:7:"isbn_13";N;s:8:"language";s:2:"en";s:10:"page_count";i:0;s:10:"categories";a:1:{i:0;s:8:"Calculus";}s:11:"description";N;s:9:"thumbnail";s:102:"https://books.google.com/books/content?id=FJXa0QEACAAJ&printsec=frontcover&img=1&zoom=2&source=gbs_api";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=FJXa0QEACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=FJXa0QEACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:100:"https://books.google.co.in/books?id=FJXa0QEACAAJ&dq=calculus+textbook&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:84:"https://books.google.com/books/about/A_Textbook_of_Calculus.html?hl=&id=FJXa0QEACAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=FJXa0QEACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:18;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"0pyC2NeVLKUC";s:5:"title";s:47:"A Course in Multivariable Calculus and Analysis";s:8:"subtitle";N;s:7:"authors";a:2:{i:0;s:18:"Sudhir R. Ghorpade";i:1;s:18:"Balmohan V. Limaye";}s:9:"publisher";s:33:"Springer Science & Business Media";s:14:"published_date";s:10:"2009-12-10";s:7:"isbn_10";s:10:"1441916202";s:7:"isbn_13";s:13:"9781441916204";s:8:"language";s:2:"en";s:10:"page_count";i:486;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:976:"This self-contained textbook gives a thorough exposition of multivariable calculus. The emphasis is on correlating general concepts and results of multivariable calculus with their counterparts in one-variable calculus. Further, the book includes genuine analogues of basic results in one-variable calculus, such as the mean value theorem and the fundamental theorem of calculus. This book is distinguished from others on the subject: it examines topics not typically covered, such as monotonicity, bimonotonicity, and convexity, together with their relation to partial differentiation, cubature rules for approximate evaluation of double integrals, and conditional as well as unconditional convergence of double series and improper double integrals. Each chapter contains detailed proofs of relevant results, along with numerous examples and a wide collection of exercises of varying degrees of difficulty, making the book useful to undergraduate and graduate students alike.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781441916204-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=0pyC2NeVLKUC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0pyC2NeVLKUC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:4;s:13:"ratings_count";i:1;s:9:"info_link";s:100:"https://books.google.co.in/books?id=0pyC2NeVLKUC&dq=calculus+textbook&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/A_Course_in_Multivariable_Calculus_and_A.html?hl=&id=0pyC2NeVLKUC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0pyC2NeVLKUC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:19;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"br0hBQAAQBAJ";s:5:"title";s:21:"Calculus with Vectors";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:14:"Jay S. Treiman";}s:9:"publisher";s:8:"Springer";s:14:"published_date";s:10:"2014-10-30";s:7:"isbn_10";s:10:"3319094386";s:7:"isbn_13";s:13:"9783319094380";s:8:"language";s:2:"en";s:10:"page_count";i:406;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1065:"Calculus with Vectors grew out of a strong need for a beginning calculus textbook for undergraduates who intend to pursue careers in STEM fields. The approach introduces vector-valued functions from the start, emphasizing the connections between one-variable and multi-variable calculus. The text includes early vectors and early transcendentals and includes a rigorous but informal approach to vectors. Examples and focused applications are well presented along with an abundance of motivating exercises. The approaches taken to topics such as the derivation of the derivatives of sine and cosine, the approach to limits and the use of "tables" of integration have been modified from the standards seen in other textbooks in order to maximize the ease with which students may comprehend the material. Additionally, the material presented is intentionally non-specific to any software or hardware platform in order to accommodate the wide variety and rapid evolution of tools used. Technology is referenced in the text and is required for a good number of problems.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9783319094380-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=br0hBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=br0hBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:1;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=br0hBQAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=br0hBQAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=br0hBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}}	1778927665
book-quality-assessor-cache-gbooks:search:v4:76e178208bb98a5a03c8fafdbde0ed04	a:20:{i:0;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"eR0rEQAAQBAJ";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";s:31:"Vector and Inner Product Spaces";s:7:"authors";a:1:{i:0;s:21:"Saurabh Chandra Maury";}s:9:"publisher";s:30:"Walter de Gruyter GmbH & Co KG";s:14:"published_date";s:10:"2024-11-18";s:7:"isbn_10";s:10:"3111516032";s:7:"isbn_13";s:13:"9783111516035";s:8:"language";s:2:"en";s:10:"page_count";i:274;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1201:"This book is a comprehensive guide to Linear Algebra and covers all the fundamental topics such as vector spaces, linear independence, basis, linear transformations, matrices, determinants, inner products, eigenvectors, bilinear forms, and canonical forms. It also introduces concepts such as fields, rings, group homomorphism, and binary operations early on, which gives students a solid foundation to understand the rest of the material. Unlike other books on Linear Algebra that are either too theory-oriented with fewer solved examples or too problem-oriented with less good quality theory, this book strikes a balance between the two. It provides easy-to-follow theorem proofs and a considerable number of worked examples with various levels of difficulty. The fundamentals of the subject are explained in a methodical and straightforward way. This book is aimed at undergraduate and graduate students of Mathematics and Engineering Mathematics who are studying Linear Algebra. It is also a useful resource for students preparing for exams in higher education competitions such as NET, GATE, lectureships, etc. The book includes some of the most recent and challenging questions from these exams.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9783111516035-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=eR0rEQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=eR0rEQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=eR0rEQAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=eR0rEQAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=eR0rEQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:1;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"c_NEBAAAQBAJ";s:5:"title";s:30:"Introduction to Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:10:"Serge Lang";}s:9:"publisher";s:33:"Springer Science & Business Media";s:14:"published_date";s:10:"2012-12-06";s:7:"isbn_10";s:10:"1461210704";s:7:"isbn_13";s:13:"9781461210702";s:8:"language";s:2:"en";s:10:"page_count";i:300;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:562:"This is a short text in linear algebra, intended for a one-term course. In the first chapter, Lang discusses the relation between the geometry and the algebra underlying the subject, and gives concrete examples of the notions which appear later in the book. He then starts with a discussion of linear equations, matrices and Gaussian elimination, and proceeds to discuss vector spaces, linear maps, scalar products, determinants, and eigenvalues. The book contains a large number of exercises, some of the routine computational type, while others are conceptual.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781461210702-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=c_NEBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=c_NEBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=c_NEBAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=c_NEBAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=c_NEBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:2;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"jM6Ml8axJ3QC";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:45:"A. R. Vasishtha, J.N. Sharma, A. K. Vasishtha";}s:9:"publisher";s:23:"Krishna Prakashan Media";s:14:"published_date";N;s:7:"isbn_10";s:10:"8182835755";s:7:"isbn_13";s:13:"9788182835757";s:8:"language";s:2:"en";s:10:"page_count";i:426;s:10:"categories";a:0:{}s:11:"description";N;s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788182835757-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=jM6Ml8axJ3QC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=jM6Ml8axJ3QC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:6;s:9:"info_link";s:97:"https://books.google.co.in/books?id=jM6Ml8axJ3QC&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:76:"https://books.google.com/books/about/Linear_Algebra.html?hl=&id=jM6Ml8axJ3QC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=jM6Ml8axJ3QC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:3;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"bUZ0AgAAQBAJ";s:5:"title";s:36:"Linear Algebra: Concepts and Methods";s:8:"subtitle";N;s:7:"authors";a:2:{i:0;s:14:"Martin Anthony";i:1;s:14:"Michele Harvey";}s:9:"publisher";s:26:"Cambridge University Press";s:14:"published_date";s:10:"2012-05-10";s:7:"isbn_10";s:10:"1107493684";s:7:"isbn_13";s:13:"9781107493681";s:8:"language";s:2:"en";s:10:"page_count";i:531;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:712:"Any student of linear algebra will welcome this textbook, which provides a thorough treatment of this key topic. Blending practice and theory, the book enables the reader to learn and comprehend the standard methods, with an emphasis on understanding how they actually work. At every stage, the authors are careful to ensure that the discussion is no more complicated or abstract than it needs to be, and focuses on the fundamental topics. The book is ideal as a course text or for self-study. Instructors can draw on the many examples and exercises to supplement their own assignments. End-of-chapter sections summarise the material to help students consolidate their learning as they progress through the book.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781107493681-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=bUZ0AgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=bUZ0AgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=bUZ0AgAAQBAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:97:"https://books.google.com/books/about/Linear_Algebra_Concepts_and_Methods.html?hl=&id=bUZ0AgAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=bUZ0AgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:4;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"iKnmDwAAQBAJ";s:5:"title";s:46:"A Textbook of B.Sc. Mathematics Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:106:"V Venkateswara Rao, N Krishnamurthy, B V S S Sarma\nS Anjaneya Sastry, S Ranganatham & Dr. R Bharavi Sharma";}s:9:"publisher";s:19:"S. Chand Publishing";s:14:"published_date";N;s:7:"isbn_10";s:10:"9352835271";s:7:"isbn_13";s:13:"9789352835270";s:8:"language";s:2:"en";s:10:"page_count";i:232;s:10:"categories";a:1:{i:0;s:7:"Science";}s:11:"description";s:217:"This "Textbook of B.Sc Mathematics" for the students studying third year first semester in all universities of Telangana state was first published in the year 1988 and has undergone several editions and many reprints.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9789352835270-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=iKnmDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=iKnmDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=iKnmDwAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=iKnmDwAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=iKnmDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:5;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"RJFeBAAAQBAJ";s:5:"title";s:33:"AN INTRODUCTION TO LINEAR ALGEBRA";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:13:"MARWAHA, ALKA";}s:9:"publisher";s:22:"PHI Learning Pvt. Ltd.";s:14:"published_date";s:10:"2014-04-15";s:7:"isbn_10";s:10:"8120349520";s:7:"isbn_13";s:13:"9788120349520";s:8:"language";s:2:"en";s:10:"page_count";i:309;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1740:"This book is meant for an introductory course in linear algebra for undergraduate students of mathematics. It deals with the concept of vector spaces and special types of functions defined on them called linear transformations or operators. The vector spaces considered in the book are finite-dimensional, a concept that involves representation of vectors in terms of a finite number of vectors which form a basis for the vector spaces. Written from a student’s perspective, this textbook explains the basic concepts in a manner that the student would be able to grasp the subject easily. Numerous solved examples and exercises given at the end of nearly each section will help the student to gain confidence in his/her analytical skills. What makes this book probably stand apart from other standard books on finite-dimensional linear algebra is the introduction to Hilbert Space Theory. The generic model of a finite-dimensional Hilbert space (real or complex) is IRn or sn but the true relevance of operators in Hilbert spaces surfaces only when they are infinite-dimensional. In order to properly comprehend the structure of an infinite-dimensional Hilbert space, it is important to grasp it at the finite-dimensional level. Although finite-dimensional Hilbert spaces are discussed comprehensively in the first eight chapters, it is only in the last three chapters that the treatment of Hilbert spaces is given in a setting which can be easily extended to defining infinite-dimensional Hilbert spaces. After going through this textbook, the students will have a clear understanding of the model of a Hilbert space in finite-dimensions and will then be able to smoothly make the transition to infinite-dimensional Hilbert Space Theory.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788120349520-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=RJFeBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=RJFeBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=RJFeBAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=RJFeBAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=RJFeBAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:6;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"Tb4sAAAAQBAJ";s:5:"title";s:35:"Linear Algebra and Its Applications";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:12:"David C. Lay";}s:9:"publisher";s:17:"Pearson Higher Ed";s:14:"published_date";s:10:"2011-11-21";s:7:"isbn_10";s:10:"0321830881";s:7:"isbn_13";s:13:"9780321830883";s:8:"language";s:2:"en";s:10:"page_count";i:576;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1221:"Linear algebra is relatively easy for students during the early stages of the course, when the material is presented in a familiar, concrete setting. But when abstract concepts are introduced, students often hit a brick wall. Instructors seem to agree that certain concepts (such as linear independence, spanning, subspace, vector space, and linear transformations), are not easily understood, and require time to assimilate. Since they are fundamental to the study of linear algebra, students' understanding of these concepts is vital to their mastery of the subject. David Lay introduces these concepts early in a familiar, concrete Rn setting, develops them gradually, and returns to them again and again throughout the text so that when discussed in the abstract, these concepts are more accessible. Note: This is the standalone book, if you want the book/access card order the ISBN below. 0321399145 / 9780321399144 Linear Algebra plus MyMathLab Getting Started Kit for Linear Algebra and Its Applications Package consists of: 0321385179 / 9780321385178 Linear Algebra and Its Applications 0321431308 / 9780321431301 MyMathLab/MyStatLab -- Glue-in Access Card 0321654064 / 9780321654069 MyMathLab Inside Star Sticker";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780321830883-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=Tb4sAAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Tb4sAAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=Tb4sAAAAQBAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:97:"https://books.google.com/books/about/Linear_Algebra_and_Its_Applications.html?hl=&id=Tb4sAAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Tb4sAAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:7;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"S0imN2tl1qwC";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";s:23:"Theory and Applications";s:7:"authors";a:2:{i:0;s:11:"Ward Cheney";i:1;s:13:"David Kincaid";}s:9:"publisher";s:27:"Jones & Bartlett Publishers";s:14:"published_date";s:4:"2012";s:7:"isbn_10";s:10:"1449613527";s:7:"isbn_13";s:13:"9781449613525";s:8:"language";s:2:"en";s:10:"page_count";i:649;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:985:"Ward Cheney and David Kincaid have developed Linear Algebra: Theory and Applications, Second Edition, a multi-faceted introductory textbook, which was motivated by their desire for a single text that meets the various requirements for differing courses within linear algebra. For theoretically-oriented students, the text guides them as they devise proofs and deal with abstractions by focusing on a comprehensive blend between theory and applications. For application-oriented science and engineering students, it contains numerous exercises that help them focus on understanding and learning not only vector spaces, matrices, and linear transformations, but uses of software tools available for use in applied linear algebra. Using a flexible design, it is an ideal textbook for instructors who wish to make their own choice regarding what material to emphasis, and to accentuate those choices with homework assignments from a large variety of exercises, both in the text and online.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781449613525-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=S0imN2tl1qwC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=S0imN2tl1qwC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=S0imN2tl1qwC&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:76:"https://books.google.com/books/about/Linear_Algebra.html?hl=&id=S0imN2tl1qwC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=S0imN2tl1qwC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:8;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"pifStNLaXGkC";s:5:"title";s:35:"Linear Algebra Thoroughly Explained";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:13:"Milan Vujicic";}s:9:"publisher";s:33:"Springer Science & Business Media";s:14:"published_date";s:10:"2007-11-16";s:7:"isbn_10";s:10:"3540746390";s:7:"isbn_13";s:13:"9783540746393";s:8:"language";s:2:"en";s:10:"page_count";i:294;s:10:"categories";a:1:{i:0;s:7:"Science";}s:11:"description";s:1309:"Milan Vujicic was Professor of Theoretical Physics at the University of Belgrade and the book is based on lectures he gave there to both undergraduate and postgraduate students over a period of several decades. He also lectured on the applications of linear algebra in particle physics at the University of Adelaide and, after retirement, taught the subject at the most basic level to Teaching Diploma students at the University of Malta. It was his success in this most recent endeavour that inspired him to write this book which sets out to explain Linear Algebra from its fundamentals to the most advanced level where he, himself, used it throughout his career to solve problems involving linear and anti-linear correlations and symmetries in quantum mechanical applications. Linear Algebra is one of the most important topics in mathematics, of interest in its own right to mathematicians, but also as an enormously powerful tool in the applied sciences, particularly in physics and engineering. A special feature of this book is its didactical approach, with a myriad of thoroughly worked examples and excellent illustrations, which allows the reader to approach the subject from any level and to proceed to that of the most advanced applications. Throughout, the subject is taught with painstaking care.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9783540746393-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=pifStNLaXGkC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=pifStNLaXGkC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=pifStNLaXGkC&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=pifStNLaXGkC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=pifStNLaXGkC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:9;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"y5we8xEEUAsC";s:5:"title";s:14:"LINEAR ALGEBRA";s:8:"subtitle";s:20:"A GEOMETRIC APPROACH";s:7:"authors";a:1:{i:0;s:13:"KUMARESAN, S.";}s:9:"publisher";s:22:"PHI Learning Pvt. Ltd.";s:14:"published_date";s:10:"2000-01-01";s:7:"isbn_10";s:10:"8120316282";s:7:"isbn_13";s:13:"9788120316287";s:8:"language";s:2:"en";s:10:"page_count";i:240;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1003:"This clear, concise and highly readable text is designed for a first course in linear algebra and is intended for undergraduate courses in mathematics. It focusses throughout on geometric explanations to make the student perceive that linear algebra is nothing but analytic geometry of n dimensions. From the very start, linear algebra is presented as an extension of the theory of simultaneous linear equations and their geometric interpretation is shown to be a recurring theme of the subject. The integration of abstract algebraic concepts with the underlying geometric notions is one of the most distinguishing features of this book — designed to help students in the pursuit of multivariable calculus and differential geometry in subsequent courses.Explanations and concepts are logically presented in a conversational tone and well-constructed writing style so that students at a variety of levels can understand the material and acquire a solid foundation in the basic skills of linear algebra.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788120316287-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=y5we8xEEUAsC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=y5we8xEEUAsC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=y5we8xEEUAsC&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=y5we8xEEUAsC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=y5we8xEEUAsC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:10;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"r28nV_sIoxwC";s:5:"title";s:27:"Linear Algebra and Geometry";s:8:"subtitle";N;s:7:"authors";a:3:{i:0;s:12:"P. K. Suetin";i:1;s:22:"Alexandra I. Kostrikin";i:2;s:10:"Yu I Manin";}s:9:"publisher";s:9:"CRC Press";s:14:"published_date";s:10:"1997-10-01";s:7:"isbn_10";s:10:"9056990497";s:7:"isbn_13";s:13:"9789056990497";s:8:"language";s:2:"en";s:10:"page_count";i:324;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:911:"This advanced textbook on linear algebra and geometry covers a wide range of classical and modern topics. Differing from existing textbooks in approach, the work illustrates the many-sided applications and connections of linear algebra with functional analysis, quantum mechanics and algebraic and differential geometry. The subjects covered in some detail include normed linear spaces, functions of linear operators, the basic structures of quantum mechanics and an introduction to linear programming. Also discussed are Kahler's metic, the theory of Hilbert polynomials, and projective and affine geometries. Unusual in its extensive use of applications in physics to clarify each topic, this comprehensice volume should be of particular interest to advanced undergraduates and graduates in mathematics and physics, and to lecturers in linear and multilinear algebra, linear programming and quantum mechanics.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9789056990497-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=r28nV_sIoxwC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=r28nV_sIoxwC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:1;s:9:"info_link";s:97:"https://books.google.co.in/books?id=r28nV_sIoxwC&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:89:"https://books.google.com/books/about/Linear_Algebra_and_Geometry.html?hl=&id=r28nV_sIoxwC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=r28nV_sIoxwC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:11;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"kyHCAgAAQBAJ";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:16:"Georgi E. Shilov";}s:9:"publisher";s:19:"Courier Corporation";s:14:"published_date";s:10:"2012-04-26";s:7:"isbn_10";s:10:"0486135047";s:7:"isbn_13";s:13:"9780486135045";s:8:"language";s:2:"en";s:10:"page_count";i:404;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:226:"Covers determinants, linear spaces, systems of linear equations, linear functions of a vector argument, coordinate transformations, the canonical form of the matrix of a linear operator, bilinear and quadratic forms, and more.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780486135045-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=kyHCAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=kyHCAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=kyHCAgAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=kyHCAgAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=kyHCAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:12;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"XAnvAAAAMAAJ";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:12:"Henry Helson";}s:9:"publisher";N;s:14:"published_date";s:4:"1996";s:7:"isbn_10";N;s:7:"isbn_13";N;s:8:"language";s:2:"en";s:10:"page_count";i:236;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";N;s:9:"thumbnail";s:102:"https://books.google.com/books/content?id=XAnvAAAAMAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=XAnvAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=XAnvAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=XAnvAAAAMAAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:76:"https://books.google.com/books/about/Linear_Algebra.html?hl=&id=XAnvAAAAMAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=XAnvAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:13;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"DrXiBQAAQBAJ";s:5:"title";s:32:"A First Course in Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:15:"Daniel Zelinsky";}s:9:"publisher";s:14:"Academic Press";s:14:"published_date";s:10:"2014-05-12";s:7:"isbn_10";s:10:"1483265005";s:7:"isbn_13";s:13:"9781483265001";s:8:"language";s:2:"en";s:10:"page_count";i:277;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:908:"A First Course in Linear Algebra provides an introduction to the algebra and geometry of vectors, matrices, and linear transformations. This book is designed as a background for second-year courses in calculus of several variables and differential equations where the theory of linear differential equations parallels that of linear algebraic equations. The topics discussed include the multiplication of vectors by scalars, vectors in n-space, planes and lines, and composites of linear mappings. The symmetric matrices and mappings, quadratic forms, change of coordinates, and effect of change of basis on matrices of linear functions are also described. This text likewise considers the computation of determinants, diagonalizable transformations, computation of eigenvalues and eigenvectors, and principal axis theorem. This publication is suitable for college students taking a course in linear algebra.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781483265001-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=DrXiBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=DrXiBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=DrXiBQAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=DrXiBQAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=DrXiBQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:14;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"REiYDwAAQBAJ";s:5:"title";s:25:"Elementary Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:2:{i:0;s:12:"Howard Anton";i:1;s:10:"Anton Kaul";}s:9:"publisher";s:17:"John Wiley & Sons";s:14:"published_date";s:10:"2019-02-20";s:7:"isbn_10";s:10:"1119268044";s:7:"isbn_13";s:13:"9781119268048";s:8:"language";s:2:"en";s:10:"page_count";i:610;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:448:"Elementary Linear Algebra 12th edition gives an elementary treatment of linear algebra that is suitable for a first course for undergraduate students. The aim is to present the fundamentals of linear algebra in the clearest possible way; pedagogy is the main consideration. Calculus is not a prerequisite, but there are clearly labeled exercises and examples (which can be omitted without loss of continuity) for students who have studied calculus.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781119268048-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=REiYDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=REiYDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=REiYDwAAQBAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:87:"https://books.google.com/books/about/Elementary_Linear_Algebra.html?hl=&id=REiYDwAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=REiYDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:15;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"WW1lDwAAQBAJ";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";N;s:7:"authors";a:2:{i:0;s:15:"M. Thamban Nair";i:1;s:14:"Arindama Singh";}s:9:"publisher";s:8:"Springer";s:14:"published_date";s:10:"2018-07-17";s:7:"isbn_10";s:10:"9811309264";s:7:"isbn_13";s:13:"9789811309267";s:8:"language";s:2:"en";s:10:"page_count";i:348;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1271:"This book introduces the fundamental concepts, techniques and results of linear algebra that form the basis of analysis, applied mathematics and algebra. Intended as a text for undergraduate students of mathematics, science and engineering with a knowledge of set theory, it discusses the concepts that are constantly used by scientists and engineers. It also lays the foundation for the language and framework for modern analysis and its applications. Divided into seven chapters, it discusses vector spaces, linear transformations, best approximation in inner product spaces, eigenvalues and eigenvectors, block diagonalisation, triangularisation, Jordan form, singular value decomposition, polar decomposition, and many more topics that are relevant to applications. The topics chosen have become well-established over the years and are still very much in use. The approach is both geometric and algebraic. It avoids distraction from the main theme by deferring the exercises to the end of each section. These exercises aim at reinforcing the learned concepts rather than as exposing readers to the tricks involved in the computation. Problems included at the end of each chapter are relatively advanced and require a deep understanding and assimilation of the topics.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9789811309267-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=WW1lDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=WW1lDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=WW1lDwAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=WW1lDwAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=WW1lDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:16;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"X1y5EAAAQBAJ";s:5:"title";s:45:"Linear Algebra With Machine Learning and Data";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:15:"Crista Arangala";}s:9:"publisher";s:9:"CRC Press";s:14:"published_date";s:10:"2023-05-09";s:7:"isbn_10";s:10:"1000856208";s:7:"isbn_13";s:13:"9781000856200";s:8:"language";s:2:"en";s:10:"page_count";i:342;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1338:"This book takes a deep dive into several key linear algebra subjects as they apply to data analytics and data mining. The book offers a case study approach where each case will be grounded in a real-world application. This text is meant to be used for a second course in applications of Linear Algebra to Data Analytics, with a supplemental chapter on Decision Trees and their applications in regression analysis. The text can be considered in two different but overlapping general data analytics categories: clustering and interpolation. Knowledge of mathematical techniques related to data analytics and exposure to interpretation of results within a data analytics context are particularly valuable for students studying undergraduate mathematics. Each chapter of this text takes the reader through several relevant case studies using real-world data. All data sets, as well as Python and R syntax, are provided to the reader through links to Github documentation. Following each chapter is a short exercise set in which students are encouraged to use technology to apply their expanding knowledge of linear algebra as it is applied to data analytics. A basic knowledge of the concepts in a first Linear Algebra course is assumed; however, an overview of key concepts is presented in the Introduction and as needed throughout the text.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781000856200-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=X1y5EAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=X1y5EAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=X1y5EAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=X1y5EAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=X1y5EAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:17;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"LvRUAAAAYAAJ";s:5:"title";s:14:"Linear Algebra";s:8:"subtitle";s:15:"An Introduction";s:7:"authors";a:1:{i:0;s:16:"Alun Owen Morris";}s:9:"publisher";s:29:"Van Nostrand Reinhold Company";s:14:"published_date";s:4:"1982";s:7:"isbn_10";N;s:7:"isbn_13";N;s:8:"language";s:2:"en";s:10:"page_count";i:220;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";N;s:9:"thumbnail";s:102:"https://books.google.com/books/content?id=LvRUAAAAYAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=LvRUAAAAYAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=LvRUAAAAYAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:97:"https://books.google.co.in/books?id=LvRUAAAAYAAJ&dq=linear+algebra&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:76:"https://books.google.com/books/about/Linear_Algebra.html?hl=&id=LvRUAAAAYAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=LvRUAAAAYAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:18;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"Kj48EQAAQBAJ";s:5:"title";s:36:"Linear Algebra with its Applications";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:14:"Ramakant Meher";}s:9:"publisher";s:9:"CRC Press";s:14:"published_date";s:10:"2025-03-07";s:7:"isbn_10";s:10:"1040336183";s:7:"isbn_13";s:13:"9781040336182";s:8:"language";s:2:"en";s:10:"page_count";i:300;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:963:"This book contains a detailed discussion of the matrix operation, its properties, and its applications in finding the solution of linear equations and determinants. Linear algebra is a subject that has found the broadest range of applications in all branches of mathematics, physical and social sciences, and engineering. It has a more significant application in information sciences and control theory. A definition of linear algebra is that it is a part of algebra which is concerned with equations of the first degree. Thus, at the fundamental level, it involves the discussion of matrices and determinants, and the solutions of systems of linear equations, which have a wide application in further discussion of this subject. Technical topics discussed in the book include: Matrices Vector spaces Eigenvalue and eigenvectors Linear transformation Inner product spaces Diagonalizations Applications to conics and quadrics Canonical forms Least squares problems";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781040336182-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=Kj48EQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Kj48EQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=Kj48EQAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=Kj48EQAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Kj48EQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:19;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"ukyjDQAAQBAJ";s:5:"title";s:58:"MATRIX AND LINEAR ALGEBRA AIDED WITH MATLAB, Third Edition";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:19:"Kanti Bhushan Datta";}s:9:"publisher";s:22:"PHI Learning Pvt. Ltd.";s:14:"published_date";s:10:"2016-12-01";s:7:"isbn_10";s:10:"8120352866";s:7:"isbn_13";s:13:"9788120352865";s:8:"language";s:2:"en";s:10:"page_count";i:717;s:10:"categories";a:1:{i:0;s:11:"Mathematics";}s:11:"description";s:1225:"With the inclusion of applications of singular value decomposition (SVD) and principal component analysis (PCA) to image compression and data analysis, this edition provides a strong foundation of linear algebra needed for a higher study in signal processing. The use of MATLAB in the study of linear algebra for a variety of computational purposes and the programmes provided in this text are the most attractive features of this book which strikingly distinguishes it from the existing linear algebra books needed as pre-requisites for the study of engineering subjects. This book is highly suitable for undergraduate as well as postgraduate students of mathematics, statistics, and all engineering disciplines. The book will also be useful to Ph.D. students for relevant mathematical resources. NEW TO THIS EDITION The Third Edition of this book includes: • Simultaneous diagonalization of two diagonalizable matrices • Comprehensive exposition of SVD with applications in shear analysis in engineering • Polar Decomposition of a matrix • Numerical experimentation with a colour and a black-and-white image compression using MATLAB • PCA methods of data analysis and image compression with a list of MATLAB codes";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788120352865-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=ukyjDQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=ukyjDQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:1;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=ukyjDQAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=ukyjDQAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=ukyjDQAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}}	1778927691
book-quality-assessor-cache-gbooks:search:v4:6897be95877ec14fb9ff692e4f052d2c	a:20:{i:0;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"0p8bEAAAQBAJ";s:5:"title";s:38:"Data Structures And Algorithms Using C";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:19:"Jyoti Prakash Singh";}s:9:"publisher";s:22:"Vikas Publishing House";s:14:"published_date";N;s:7:"isbn_10";s:10:"8125950877";s:7:"isbn_13";s:13:"9788125950875";s:8:"language";s:2:"en";s:10:"page_count";i:473;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:568:"The book Data Structures and Algorithms Using C aims at helping students develop both programming and algorithm analysis skills simultaneously so that they can design programs with the maximum amount of efficiency. The book uses C language since it allows basic data structures to be implemented in a variety of ways. Data structure is a central course in the curriculum of all computer science programs. This book follows the syllabus of Data Structures and Algorithms course being taught in B Tech, BCA and MCA programs of all institutes under most universities.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788125950875-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=0p8bEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0p8bEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=0p8bEAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=0p8bEAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0p8bEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:1;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"Qq3UCgAAQBAJ";s:5:"title";s:30:"Data Structures And Algorithms";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:13:"Shi-kuo Chang";}s:9:"publisher";s:16:"World Scientific";s:14:"published_date";s:10:"2003-09-29";s:7:"isbn_10";s:10:"9814486159";s:7:"isbn_13";s:13:"9789814486156";s:8:"language";s:2:"en";s:10:"page_count";i:361;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:738:"This is an excellent, up-to-date and easy-to-use text on data structures and algorithms that is intended for undergraduates in computer science and information science. The thirteen chapters, written by an international group of experienced teachers, cover the fundamental concepts of algorithms and most of the important data structures as well as the concept of interface design. The book contains many examples and diagrams. Whenever appropriate, program codes are included to facilitate learning.This book is supported by an international group of authors who are experts on data structures and algorithms, through its website at www.cs.pitt.edu/~jung/GrowingBook/, so that both teachers and students can benefit from their expertise.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9789814486156-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=Qq3UCgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Qq3UCgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=Qq3UCgAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=Qq3UCgAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=Qq3UCgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:2;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"UqmYAgAAQBAJ";s:5:"title";s:38:"Data Structures and Algorithms in Java";s:8:"subtitle";N;s:7:"authors";a:3:{i:0;s:19:"Michael T. Goodrich";i:1;s:16:"Roberto Tamassia";i:2;s:21:"Michael H. Goldwasser";}s:9:"publisher";s:17:"John Wiley & Sons";s:14:"published_date";s:10:"2014-01-28";s:7:"isbn_10";s:10:"1118771338";s:7:"isbn_13";s:13:"9781118771334";s:8:"language";s:2:"en";s:10:"page_count";i:736;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:812:"The design and analysis of efficient data structures has long been recognized as a key component of the Computer Science curriculum. Goodrich, Tomassia and Goldwasser's approach to this classic topic is based on the object-oriented paradigm as the framework of choice for the design of data structures. For each ADT presented in the text, the authors provide an associated Java interface. Concrete data structures realizing the ADTs are provided as Java classes implementing the interfaces. The Java code implementing fundamental data structures in this book is organized in a single Java package, net.datastructures. This package forms a coherent library of data structures and algorithms in Java specifically designed for educational purposes in a way that is complimentary with the Java Collections Framework.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781118771334-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=UqmYAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=UqmYAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=UqmYAgAAQBAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:100:"https://books.google.com/books/about/Data_Structures_and_Algorithms_in_Java.html?hl=&id=UqmYAgAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=UqmYAgAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:3;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"VRaxY61mw5cC";s:5:"title";s:39:"Data Structures and Algorithms Using C+";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:18:"Akepogu Ananda Rao";}s:9:"publisher";s:23:"Pearson Education India";s:14:"published_date";s:7:"2010-09";s:7:"isbn_10";s:10:"8131755673";s:7:"isbn_13";s:13:"9788131755679";s:8:"language";s:2:"en";s:10:"page_count";i:580;s:10:"categories";a:1:{i:0;s:10:"Algorithms";}s:11:"description";s:354:"Data Structures and Algorithms Using C++ helps students to master data structures, their algorithms and the analysis of complexities of these algorithms. Each chapter includes an Abstract Data Type (ADT) and applications along with a detailed explanation of the topics. This book meets the requirements of the course curricula of all Indian universities.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788131755679-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=VRaxY61mw5cC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=VRaxY61mw5cC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";d:4.5;s:13:"ratings_count";i:2;s:9:"info_link";s:113:"https://books.google.co.in/books?id=VRaxY61mw5cC&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:101:"https://books.google.com/books/about/Data_Structures_and_Algorithms_Using_C+.html?hl=&id=VRaxY61mw5cC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=VRaxY61mw5cC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:4;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"K_aEDwAAQBAJ";s:5:"title";s:41:"JavaScript Data Structures and Algorithms";s:8:"subtitle";s:96:"An Introduction to Understanding and Implementing Core Data Structure and Algorithm Fundamentals";s:7:"authors";a:1:{i:0;s:10:"Sammie Bae";}s:9:"publisher";s:6:"Apress";s:14:"published_date";s:10:"2019-01-23";s:7:"isbn_10";s:10:"1484239881";s:7:"isbn_13";s:13:"9781484239889";s:8:"language";s:2:"en";s:10:"page_count";i:362;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:1683:"Explore data structures and algorithm concepts and their relation to everyday JavaScript development. A basic understanding of these ideas is essential to any JavaScript developer wishing to analyze and build great software solutions. You'll discover how to implement data structures such as hash tables, linked lists, stacks, queues, trees, and graphs. You'll also learn how a URL shortener, such as bit.ly, is developed and what is happening to the data as a PDF is uploaded to a webpage. This book covers the practical applications of data structures and algorithms to encryption, searching, sorting, and pattern matching. It is crucial for JavaScript developers to understand how data structures work and how to design algorithms. This book and the accompanying code provide that essential foundation for doing so. With JavaScript Data Structures and Algorithms you can start developing your knowledge and applying it to your JavaScript projects today. What You'll Learn Review core data structure fundamentals: arrays, linked-lists, trees, heaps, graphs, and hash-table Review core algorithm fundamentals: search, sort, recursion, breadth/depth first search, dynamic programming, bitwise operators Examine how the core data structure and algorithms knowledge fits into context of JavaScript explained using prototypical inheritance and native JavaScript objects/data types Take a high-level look at commonly used design patterns in JavaScript Who This Book Is For Existing web developers and software engineers seeking to develop or revisit their fundamental data structures knowledge; beginners and students studying JavaScript independently or via a course or coding bootcamp.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781484239889-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=K_aEDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=K_aEDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=K_aEDwAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=K_aEDwAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=K_aEDwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:5;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"ld9QAAAAMAAJ";s:5:"title";s:52:"An Introduction to Data Structures with Applications";s:8:"subtitle";N;s:7:"authors";a:2:{i:0;s:18:"Jean-Paul Tremblay";i:1;s:14:"P. G. Sorenson";}s:9:"publisher";s:21:"McGraw-Hill Companies";s:14:"published_date";s:4:"1984";s:7:"isbn_10";N;s:7:"isbn_13";N;s:8:"language";s:2:"en";s:10:"page_count";i:888;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:545:"This text is designed for a course in data structures, to introduce students to concepts and terminology in a way that permits a view of computer science as a unified discipline, with an emphasis on problem-solving. This second edition has improvements which include an increased formalization of algorithmic language, more structured algorithms, use of Pascal, new exercises, and more analysis of algorithms. This edition assumes basic familiarity with assembly languages, Pascal, and combinatorial mathematics (including recurrence relations).";s:9:"thumbnail";s:102:"https://books.google.com/books/content?id=ld9QAAAAMAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=ld9QAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=ld9QAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";d:4.5;s:13:"ratings_count";i:2;s:9:"info_link";s:113:"https://books.google.co.in/books?id=ld9QAAAAMAAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:101:"https://books.google.com/books/about/An_Introduction_to_Data_Structures_with.html?hl=&id=ld9QAAAAMAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=ld9QAAAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10: