bility";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:7;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"0s5MkdzPEBUC";s:5:"title";s:45:"Data Structures,Algorithms&Applications Inc++";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:15:"S Silicon Press";}s:9:"publisher";s:18:"Universities Press";s:14:"published_date";N;s:7:"isbn_10";s:10:"817371522X";s:7:"isbn_13";s:13:"9788173715228";s:8:"language";s:2:"en";s:10:"page_count";i:826;s:10:"categories";a:0:{}s:11:"description";N;s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788173715228-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=0s5MkdzPEBUC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0s5MkdzPEBUC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:4;s:13:"ratings_count";i:9;s:9:"info_link";s:113:"https://books.google.co.in/books?id=0s5MkdzPEBUC&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:101:"https://books.google.com/books/about/Data_Structures_Algorithms_Applications.html?hl=&id=0s5MkdzPEBUC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=0s5MkdzPEBUC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:8;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"MhDSBwAAQBAJ";s:5:"title";s:46:"Data Structures and Algorithms: A First Course";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:15:"Iain T. Adamson";}s:9:"publisher";s:33:"Springer Science & Business Media";s:14:"published_date";s:10:"2012-12-06";s:7:"isbn_10";s:10:"1447110234";s:7:"isbn_13";s:13:"9781447110231";s:8:"language";s:2:"en";s:10:"page_count";i:412;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:876:"All young computer scientists who aspire to write programs must learn something about algorithms and data structures. This book does exactly that. Based on lecture courses developed by the author over a number of years the book is written in an informal and friendly way specifically to appeal to students. The book is divided into four parts: the first on Data Structures introduces a variety of structures and the fundamental operations associated with them, together with descriptions of how they are implemented in Pascal; the second discusses algorithms and the notion of complexity; Part III is concerned with the description of successively more elaborate structures for the storage of records and algorithms for retrieving a record from such a structure by means of its key; and finally, Part IV consists of very full solutions to nearly all the exercises in the book.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781447110231-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=MhDSBwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=MhDSBwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=MhDSBwAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=MhDSBwAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=MhDSBwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:9;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"wt4pAQAAMAAJ";s:5:"title";s:43:"Data Structures & Algorithm Analysis in C++";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:16:"Mark Allen Weiss";}s:9:"publisher";s:22:"Addison Wesley Longman";s:14:"published_date";s:4:"1999";s:7:"isbn_10";N;s:7:"isbn_13";N;s:8:"language";s:2:"en";s:10:"page_count";i:614;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:726:"In this text, readers are able to look at specific problems and see how careful implementations can reduce the time constraint for large amounts of data from several years to less than a second. Class templates are used to describe generic data structures and first-class versions of vector and string classes are used. Included is an appendix on a Standard Template Library (STL). This text is for readers who want to learn good programming and algorithm analysis skills simultaneously so that they can develop such programs with the maximum amount of efficiency. Readers should have some knowledge of intermediate programming, including topics as object-based programming and recursion, and some background in discrete math.";s:9:"thumbnail";s:102:"https://books.google.com/books/content?id=wt4pAQAAMAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=wt4pAQAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=wt4pAQAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=wt4pAQAAMAAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/Data_Structures_Algorithm_Analysis_in_C+.html?hl=&id=wt4pAQAAMAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=wt4pAQAAMAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:10;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"83RWbPynhkgC";s:5:"title";s:43:"Data Structures and Algorithm Analysis in C";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:5:"Weiss";}s:9:"publisher";s:23:"Pearson Education India";s:14:"published_date";s:7:"1997-09";s:7:"isbn_10";s:10:"8177583581";s:7:"isbn_13";s:13:"9788177583588";s:8:"language";s:2:"en";s:10:"page_count";i:532;s:10:"categories";a:1:{i:0;s:10:"Algorithms";}s:11:"description";s:313:"In The Second Edition Of This Best-Selling Book, The Author Continues To Refine And Enhance His Innovative Approach To Algorithms And Data Structures. Using A C Implementation, He Highlights Conceptual Topics, Focusing On Adts And The Analysis Of Algorithms For Efficiency As Well As Performance And Running Time.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788177583588-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=83RWbPynhkgC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=83RWbPynhkgC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:4;s:13:"ratings_count";i:2;s:9:"info_link";s:113:"https://books.google.co.in/books?id=83RWbPynhkgC&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/Data_Structures_and_Algorithm_Analysis_i.html?hl=&id=83RWbPynhkgC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=83RWbPynhkgC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:11;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"JPkBDj1C53YC";s:5:"title";s:41:"Data Structures and Algorithms Using Java";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:18:"William McAllister";}s:9:"publisher";s:27:"Jones & Bartlett Publishers";s:14:"published_date";s:10:"2008-12-17";s:7:"isbn_10";s:10:"1449612865";s:7:"isbn_13";s:13:"9781449612863";s:8:"language";s:2:"en";s:10:"page_count";i:597;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:1390:"With an accessible writing style and manageable amount of content, Data Structures and Algorithms Using Java is the ideal text for your course. This outstanding text correlates to the recommended syllabus put forth by the Association of Computing Machinery standard curriculum guidelines. The author has produced a resource that is more readable and instructional than any other, without compromising the scope of the ACM CS103, Data Structures and Algorithms, course material. The text’s unique, student-friendly pedagogical approach and organizational structure will keep students engaged in the process of self-directed investigative discovery both inside and outside the classroom. The pedagogical features of the text, based on the author’s 30 years of teaching experience, include succinct code examples, a unique common template used as the organizational basis of each chapter, the use of pseudocode to present the major algorithms developed in the text, nearly 300 carefully designed figures, and a concise review of Java. This text covers the material of the Association of Computing Machinery standard curriculum courses CS103i and CS103o, Data Structures and Algorithms, as defined in the IEEE/ACM Computing Curricular 2001 Computer Science Final Report. It is intended for use within the departments of Computer Science, CIS, and Electrical Engineering. © 2009 | 580 pages";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781449612863-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=JPkBDj1C53YC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=JPkBDj1C53YC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=JPkBDj1C53YC&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/Data_Structures_and_Algorithms_Using_Jav.html?hl=&id=JPkBDj1C53YC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=JPkBDj1C53YC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:12;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"q_NxAjqWDGoC";s:5:"title";s:37:"Data Structures and Algorithms in C++";s:8:"subtitle";N;s:7:"authors";a:3:{i:0;s:19:"Michael T. Goodrich";i:1;s:16:"Roberto Tamassia";i:2;s:14:"David M. Mount";}s:9:"publisher";s:17:"John Wiley & Sons";s:14:"published_date";s:10:"2011-02-22";s:7:"isbn_10";s:10:"0470383275";s:7:"isbn_13";s:13:"9780470383278";s:8:"language";s:2:"en";s:10:"page_count";i:739;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:1005:"This second edition of Data Structures and Algorithms in C++ is designed to provide an introduction to data structures and algorithms, including their design, analysis, and implementation. The authors offer an introduction to object-oriented design with C++ and design patterns, including the use of class inheritance and generic programming through class and function templates, and retain a consistent object-oriented viewpoint throughout the book. This is a “sister” book to Goodrich & Tamassia’s Data Structures and Algorithms in Java, but uses C++ as the basis language instead of Java. This C++ version retains the same pedagogical approach and general structure as the Java version so schools that teach data structures in both C++ and Java can share the same core syllabus. In terms of curricula based on the IEEE/ACM 2001 Computing Curriculum, this book is appropriate for use in the courses CS102 (I/O/B versions), CS103 (I/O/B versions), CS111 (A version), and CS112 (A/I/O/F/H versions).";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780470383278-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=q_NxAjqWDGoC&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=q_NxAjqWDGoC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";i:5;s:13:"ratings_count";i:1;s:9:"info_link";s:113:"https://books.google.co.in/books?id=q_NxAjqWDGoC&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:99:"https://books.google.com/books/about/Data_Structures_and_Algorithms_in_C++.html?hl=&id=q_NxAjqWDGoC";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=q_NxAjqWDGoC&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:13;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"IlylEAAAQBAJ";s:5:"title";s:30:"Data Structures and Algorithms";s:8:"subtitle";N;s:7:"authors";a:3:{i:0;s:10:"C V Sastry";i:1;s:13:"CH Rajaramesh";i:2;s:12:"Rakesh Nayak";}s:9:"publisher";s:25:"I K International Pvt Ltd";s:14:"published_date";s:10:"2018-01-13";s:7:"isbn_10";s:10:"9385909843";s:7:"isbn_13";s:13:"9789385909849";s:8:"language";s:2:"en";s:10:"page_count";i:305;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:547:"This book in an outcome of long years of teaching experience for undergraduate as well as post graduate students, and is an attempt to put together all the essential topics of data structures and Algorithms for easy reference. The under-graduate students of computer science and engineering, post-graduate students of computer applications and computer science and engineering will find this book very useful. It contains several multiple choice questions under each chapter which will be useful for those who aspire to write the GATE examination.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9789385909849-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=IlylEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=IlylEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=IlylEAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=IlylEAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=IlylEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:14;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"sYUxEAAAQBAJ";s:5:"title";s:39:"Advanced Algorithms and Data Structures";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:17:"Marcello La Rocca";}s:9:"publisher";s:18:"Simon and Schuster";s:14:"published_date";s:10:"2021-06-29";s:7:"isbn_10";s:10:"1617295485";s:7:"isbn_13";s:13:"9781617295485";s:8:"language";s:2:"en";s:10:"page_count";i:766;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:673:"Can you improve the speed and efficiency of your applications without investing in new hardware? Well, yest, you an: Innovations in algorithms and data structures have led to huge advances in application performance. Pick up this book to discover a collection of advanced algorithms that will make you a more effective developer. "Advanced algorithms and data structures" introduces a collection of algorithms for complex programming challenges in data analysis, machine learning, and graph computing. You'll discover cutting-edge approaches to a variety of tricky scenarios. You'll even learn to design your own data structures for projects that require a custom solution.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9781617295485-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=sYUxEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=sYUxEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=sYUxEAAAQBAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:101:"https://books.google.com/books/about/Advanced_Algorithms_and_Data_Structures.html?hl=&id=sYUxEAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=sYUxEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:25:"ALLOWED_FOR_ACCESSIBILITY";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:15;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"iEs7BAAAQBAJ";s:5:"title";s:41:"Data Structures and Algorithms Using C++:";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:3:"Rao";}s:9:"publisher";s:23:"Pearson Education India";s:14:"published_date";s:4:"1900";s:7:"isbn_10";s:10:"8131753778";s:7:"isbn_13";s:13:"9788131753774";s:8:"language";s:2:"en";s:10:"page_count";i:578;s:10:"categories";a:1:{i:0;s:10:"Algorithms";}s:11:"description";s:248:"Data Structures and Algorithms Using C++ helps students master data structures, their algorithms and the analysis of complexities of these algorithms. Each chapter includes an Abstract Data Type (ADT) and applications along with a detailed explanat";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9788131753774-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=iEs7BAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=iEs7BAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=iEs7BAAAQBAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/Data_Structures_and_Algorithms_Using_C++.html?hl=&id=iEs7BAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=iEs7BAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:16;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"FjyfQgAACAAJ";s:5:"title";s:45:"Data Structures and Algorithm Analysis in C++";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:16:"Mark Allen Weiss";}s:9:"publisher";s:33:"Addison Wesley Publishing Company";s:14:"published_date";s:4:"2006";s:7:"isbn_10";s:10:"0321375319";s:7:"isbn_13";s:13:"9780321375315";s:8:"language";s:2:"en";s:10:"page_count";i:0;s:10:"categories";a:1:{i:0;s:10:"Algorithms";}s:11:"description";s:1043:"Mark Allen Weiss' innovative approach to algorithms and data structures teaches the simultaneous development of sound analytical and programming skills for the advanced data structures course. Readers learn how to reduce time constraints and develop programs efficiently by analyzing the feasibility of an algorithm before it is coded. The C++ language is brought up-to-date and simplified, and the Standard Template Library is now fully incorporated throughout the text. This Third Edition also features significantly revised coverage of lists, stacks, queues, and trees and an entire chapter dedicated to amortized analysis and advanced data structures such as the Fibonacci heap. Known for its clear and friendly writing style, Data Structures and Algorithm Analysis in C++ is logically organized to cover advanced data structures topics from binary heaps to sorting to NP-completeness. Figures and examples illustrating successive stages of algorithms contribute to Weiss' careful, rigorous and in-depth analysis of each type of algorithm.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780321375315-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=FjyfQgAACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=FjyfQgAACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:13:"pdf_available";b:0;s:14:"epub_available";b:0;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:113:"https://books.google.co.in/books?id=FjyfQgAACAAJ&dq=data+structures+and+algorithms&hl=&as_pt=BOOKS&source=gbs_api";s:21:"canonical_volume_link";s:102:"https://books.google.com/books/about/Data_Structures_and_Algorithm_Analysis_i.html?hl=&id=FjyfQgAACAAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=FjyfQgAACAAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:0;s:11:"viewability";s:8:"NO_PAGES";s:25:"text_to_speech_permission";s:7:"ALLOWED";s:13:"public_domain";b:0;s:13:"pdf_available";b:0;s:17:"pdf_download_link";N;s:14:"epub_available";b:0;s:18:"epub_download_link";N;}}i:17;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"dNnPEAAAQBAJ";s:5:"title";s:38:"Data Structures & Algorithms in Python";s:8:"subtitle";N;s:7:"authors";a:3:{i:0;s:13:"Robert Lafore";i:1;s:11:"Alan Broder";i:2;s:12:"John Canning";}s:9:"publisher";s:27:"Addison-Wesley Professional";s:14:"published_date";s:10:"2022-09-06";s:7:"isbn_10";s:10:"0134855892";s:7:"isbn_13";s:13:"9780134855899";s:8:"language";s:2:"en";s:10:"page_count";i:1458;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:1812:"LEARN HOW TO USE DATA STRUCTURES IN WRITING HIGH PERFORMANCE PYTHON PROGRAMS AND ALGORITHMS This practical introduction to data structures and algorithms can help every programmer who wants to write more efficient software. Building on Robert Lafore's legendary Java-based guide, this book helps you understand exactly how data structures and algorithms operate. You'll learn how to efficiently apply them with the enormously popular Python language and scale your code to handle today's big data challenges. Throughout, the authors focus on real-world examples, communicate key ideas with intuitive, interactive visualizations, and limit complexity and math to what you need to improve performance. Step-by-step, they introduce arrays, sorting, stacks, queues, linked lists, recursion, binary trees, 2-3-4 trees, hash tables, spatial data structures, graphs, and more. Their code examples and illustrations are so clear, you can understand them even if you're a near-beginner, or your experience is with other procedural or object-oriented languages. Build core computer science skills that take you beyond merely “writing code” Learn how data structures make programs (and programmers) more efficient See how data organization and algorithms affect how much you can do with today's, and tomorrow's, computing resources Develop data structure implementation skills you can use in any language Choose the best data structure(s) and algorithms for each programming problem—and recognize which ones to avoid Data Structures & Algorithms in Python is packed with examples, review questions, individual and team exercises, thought experiments, and longer programming projects. It's ideal for both self-study and classroom settings, and either as a primary text or as a complement to a more formal presentation.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780134855899-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=dNnPEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=dNnPEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:13:"pdf_available";b:1;s:14:"epub_available";b:1;s:8:"metadata";a:13:{s:14:"average_rating";N;s:13:"ratings_count";N;s:9:"info_link";s:74:"https://play.google.com/store/books/details?id=dNnPEAAAQBAJ&source=gbs_api";s:21:"canonical_volume_link";s:59:"https://play.google.com/store/books/details?id=dNnPEAAAQBAJ";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=dNnPEAAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:10:"embeddable";b:1;s:11:"viewability";s:7:"PARTIAL";s:25:"text_to_speech_permission";s:25:"ALLOWED_FOR_ACCESSIBILITY";s:13:"public_domain";b:0;s:13:"pdf_available";b:1;s:17:"pdf_download_link";N;s:14:"epub_available";b:1;s:18:"epub_download_link";N;}}i:18;a:21:{s:6:"source";s:12:"google_books";s:11:"external_id";s:12:"iFc0DwAAQBAJ";s:5:"title";s:38:"Data Structures and Algorithms in Java";s:8:"subtitle";N;s:7:"authors";a:1:{i:0;s:13:"Robert Lafore";}s:9:"publisher";s:15:"Sams Publishing";s:14:"published_date";s:10:"2017-09-06";s:7:"isbn_10";s:10:"0134847997";s:7:"isbn_13";s:13:"9780134847993";s:8:"language";s:2:"en";s:10:"page_count";i:1408;s:10:"categories";a:1:{i:0;s:9:"Computers";}s:11:"description";s:1019:"Data Structures and Algorithms in Java, Second Edition is designed to be easy to read and understand although the topic itself is complicated. Algorithms are the procedures that software programs use to manipulate data structures. Besides clear and simple example programs, the author includes a workshop as a small demonstration program executable on a Web browser. The programs demonstrate in graphical form what data structures look like and how they operate. In the second edition, the program is rewritten to improve operation and clarify the algorithms, the example programs are revised to work with the latest version of the Java JDK, and questions and exercises will be added at the end of each chapter making the book even more useful. Educational Supplement Suggested solutions to the programming projects found at the end of each chapter are made available to instructors at recognized educational institutions. This educational supplement can be found at www.prenhall.com, in the Instructor Resource Center.";s:9:"thumbnail";s:71:"https://covers.openlibrary.org/b/isbn/9780134847993-M.jpg?default=false";s:12:"preview_link";s:83:"https://play.google.com/books/reader?id=iFc0DwAAQBAJ&hl=&as_pt=BOOKS&source=gbs_api";s:11:"reader_link";s:83:"https://play.google.com/books/reader?id=iFc0D